import { LightningElement } from 'lwc';
export default class SelectBasic extends LightningElement {
    value = '';
    get options() {
        return [
            { label: 'choose quantity...', value: '' },
            { label: 'one', value: '1' },
            { label: 'two', value: '2' },
            { label: 'three', value: '3' },
        ];
    }
    handleChange(event) {
        this.value = event.detail.value;
    }
}
